export function init(element, dotNetRef) {
    const events = ["mousemove", "keydown", "click", "scroll"];
    const handler = () => dotNetRef.invokeMethodAsync("OnActivityDetected");

    for (const evt of events) {
        element.addEventListener(evt, handler, { passive: true });
    }

    return {
        dispose() {
            for (const evt of events) {
                element.removeEventListener(evt, handler);
            }
        }
    };
}

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_d72dece519ab4cceb56583aad76edf1d.Components;

public partial class UserActivityTracker : IAsyncDisposable
{
    [Inject] private IJSRuntime JS { get; set; } = default!;

    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }

    private IJSObjectReference? module;
    private IJSObjectReference? jsHandle;
    private DotNetObjectReference<UserActivityTracker>? dotNetRef;
    private CancellationTokenSource? delayCts;
    private bool isIdle;
    private int timeoutSeconds;

    protected override void OnParametersSet()
    {
        timeoutSeconds = TimeoutSeconds;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        dotNetRef = DotNetObjectReference.Create(this);
        module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./Components/UserActivityTracker.razor.js");
        jsHandle = await module.InvokeAsync<IJSObjectReference>(
            "init", element, dotNetRef);

        ResetTimer();
    }

    [JSInvokable]
    public async Task OnActivityDetected()
    {
        if (isIdle)
        {
            isIdle = false;
            await OnActive.InvokeAsync();
        }

        ResetTimer();
    }

    private void ResetTimer()
    {
        delayCts?.Cancel();
        delayCts?.Dispose();
        delayCts = new CancellationTokenSource();

        _ = RunIdleTimer(delayCts.Token);
    }

    private async Task RunIdleTimer(CancellationToken token)
    {
        try
        {
            await Task.Delay(timeoutSeconds * 1000, token);

            if (!token.IsCancellationRequested)
            {
                isIdle = true;
                await OnIdle.InvokeAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Timer was reset ‚Äî expected.
        }
        catch (Exception ex)
        {
            await DispatchExceptionAsync(ex);
        }
    }

    public async ValueTask DisposeAsync()
